using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
    {
        // EF Core 9 removed sync I/O support for Cosmos; opt back in if needed
        // during migration, but plan to move all callers to async.
        optionsBuilder.ConfigureWarnings(w =>
            w.Ignore(Microsoft.EntityFrameworkCore.Diagnostics.CoreEventId.SyncNotSupported));
    }
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Breaking change: HasIndex() now throws for Cosmos — removed.

        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // Breaking change: EF Core 9 renamed the discriminator property
            // from "Discriminator" to "$type". Existing 500K documents still
            // store "Discriminator", so we must keep the old property name.
            entity.HasDiscriminator<string>("Discriminator");

            // Breaking change: EF Core 9 changed the id format from
            // "EntityName|KeyValue" (e.g. "Product|123") to just "KeyValue".
            // Existing documents use the old format, so we preserve it with
            // an explicit id factory.
            entity.HasPartitionKey(p => p.Id);
            entity.Property(p => p.Id)
                .ToJsonProperty("id")
                .HasValueGenerator<LegacyIdValueGenerator>();
        });
    }
}

// Generates id values in the legacy "Product|<key>" format so new documents
// are consistent with existing ones and EF Core can still find old documents.
class LegacyIdValueGenerator : Microsoft.EntityFrameworkCore.ValueGeneration.ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;
    public override string Next(Microsoft.EntityFrameworkCore.ChangeTracking.EntityEntry entry)
        => $"Product|{entry.Property("Id").CurrentValue}";
}

class Product { public int Id { get; set; } public string Sku { get; set; } }

